mapper.select:
SELECT count(*) FROM plan p LEFT OUTER JOIN item i on p.plan_item = i.item_id WHERE plan_usage = 'Y'
AND p.plan_edate <= #{planSearchSdate}
AND p.plan_sdate <= #{planSearchEdate}
AND p.plan_status = #{searchType}
AND ( UPPER(p.plan_id) LIKE TRIM(UPPER('%' || #{searchKeyword} || '%')) or UPPER(p.plan_item) LIKE TRIM(UPPER('%' || #{searchKeyword} || '%')) or UPPER(i.item_name) LIKE TRIM(UPPER('%' || #{searchKeyword} || '%')) )
AND (
p.plan_status = 20
p.plan_status = 10
p.plan_status = 30
p.plan_status = 40
p.plan_status = 0
)

SELECT * FROM ( SELECT rownum rn, plan.* FROM ( SELECT p.plan_id planId, p.plan_item planItem, i.item_name planItemName, i.item_unit planItemNnit, p.plan_fin_qty planFinQty, p.plan_wp_qty planWpQty, p.plan_sdate planSdate, p.plan_edate planEdate, p.plan_status planStatus, p.plan_director planDirector, d.emp_name planDname, p.plan_cdate planCdate, p.plan_mdate planMdate FROM plan p LEFT OUTER JOIN item i ON p.plan_item = i.ITEM_ID LEFT OUTER JOIN emp d ON d.emp_id = p.plan_director WHERE plan_usage = 'Y'
AND p.plan_edate <= #{planDTO.planSearchSdate}
AND p.plan_sdate <= #{planDTO.planSearchEdate}
AND p.plan_status = #{planDTO.searchType}
AND ( UPPER(p.plan_id) LIKE TRIM(UPPER('%' || #{planDTO.searchKeyword} || '%')) or UPPER(p.plan_item) LIKE TRIM(UPPER('%' || #{planDTO.searchKeyword} || '%')) or UPPER(i.item_name) LIKE TRIM(UPPER('%' || #{planDTO.searchKeyword} || '%')) )
) plan WHERE 1 = 1
AND (
plan.plan_status = 20
plan.plan_status = 10
plan.plan_status = 30
plan.plan_status = 40
plan.plan_status = 0
)
) WHERE rn BETWEEN #{page.startRow} AND #{page.endRow}

SELECT COUNT(*) AS totalCnt, SUM(CASE WHEN p.plan_status = 20 THEN 1 ELSE 0 END) AS ingCnt, SUM(CASE WHEN p.plan_status = 10 THEN 1 ELSE 0 END) AS waitCnt, SUM(CASE WHEN p.plan_status = 30 THEN 1 ELSE 0 END) AS finCnt, SUM(CASE WHEN p.plan_status = 40 THEN 1 ELSE 0 END) AS stopCnt, SUM(CASE WHEN p.plan_status = 0 THEN 1 ELSE 0 END) AS etcCnt FROM plan p LEFT OUTER JOIN item i ON p.plan_item = i.item_id WHERE p.plan_usage = 'Y'
AND p.plan_edate >= #{planSearchSdate}
AND p.plan_sdate <= #{planSearchEdate}
AND p.plan_status = #{searchType}
AND ( UPPER(p.plan_id) LIKE TRIM(UPPER('%' || #{searchKeyword} || '%')) OR UPPER(p.plan_item) LIKE TRIM(UPPER('%' || #{searchKeyword} || '%')) OR UPPER(i.item_name) LIKE TRIM(UPPER('%' || #{searchKeyword} || '%')) )
